프로젝트 `D:\16. 자동화 도구\safeAutoTest`에서 작업합니다. 다음 모듈들이 이미 커밋돼 있습니다:
- `lib/site-types.ts`
- `lib/browser-bootstrap.ts`
- `lib/site-crawler.ts` (CrawlPage, crawl, VisitRecord export 포함)
- `lib/visual-diff.ts` (captureMasked, compareImages)
- `lib/site-run-progress.ts` (setSiteRunProgress, updateSiteRunProgress)

**목표:** `lib/site-runner.ts`를 생성하고 커밋합니다. 단위 테스트는 없음 (e2e Task 20에서 검증).

**규칙:** 이 파일만 건드리세요. 다른 파일 절대 수정 금지.

---

**`lib/site-runner.ts` 생성:**

```ts
import { createHash } from "node:crypto";
import fs from "node:fs";
import path from "node:path";
import { launchBrowser, newSiteContext } from "./browser-bootstrap.ts";
import { crawl, type CrawlPage, type VisitRecord } from "./site-crawler.ts";
import { captureMasked } from "./visual-diff.ts";
import { setSiteRunProgress, updateSiteRunProgress } from "./site-run-progress.ts";
import type { Site, SitePageCapture, SiteRunResult } from "./site-types.ts";

export async function runSite(site: Site): Promise<SiteRunResult> {
  const runId = new Date().toISOString().replace(/[:.]/g, "-").slice(0, 19);
  const startedAt = new Date().toISOString();

  setSiteRunProgress({
    siteId: site.id, runId, status: "running",
    startedAt, updatedAt: startedAt,
    visited: 0, total: site.crawl.maxPages,
  });

  const runDir = path.join("data", "sites", site.id, "runs", runId);
  fs.mkdirSync(runDir, { recursive: true });

  const browser = await launchBrowser();
  const context = await newSiteContext(browser, {
    storageStatePath: site.storageStatePath,
    viewport: site.visual.viewport,
  });
  const page = await context.newPage();

  const crawlPage: CrawlPage = {
    async goto(url) {
      try {
        const response = await page.goto(url, { waitUntil: "load" });
        return response ? { status: () => response.status(), url: () => page.url() } : null;
      } catch {
        return null;
      }
    },
    async getLinks() {
      return page.$$eval("a[href]", (as) => (as as HTMLAnchorElement[]).map((a) => a.href));
    },
    url() { return page.url(); },
  };

  const pages: SitePageCapture[] = [];
  let pageIndex = 0;

  const captureCurrent = async (record: VisitRecord): Promise<void> => {
    pageIndex += 1;
    const fileBase = `page-${String(pageIndex).padStart(3, "0")}`;

    const screenshotPath = site.visual.enabled
      ? path.join(runDir, `${fileBase}.png`)
      : undefined;
    if (screenshotPath) {
      await captureMasked(page, site.visual, screenshotPath);
    }

    let domHash = "";
    let domSerialized = "";
    if (site.dom.enabled) {
      domSerialized = await page.evaluate(BROWSER_NORMALIZE_FN, site.dom);
      domHash = createHash("sha256").update(domSerialized).digest("hex");
    }

    pages.push({
      url: record.url,
      finalUrl: record.finalUrl,
      httpStatus: record.httpStatus,
      domHash, domSerialized,
      screenshotPath: screenshotPath ? path.relative(process.cwd(), screenshotPath) : undefined,
      capturedAt: new Date().toISOString(),
    });

    updateSiteRunProgress(site.id, (p) => ({
      ...p, visited: pages.length, currentUrl: record.url,
      updatedAt: new Date().toISOString(),
    }));
  };

  let outcome;
  try {
    outcome = await crawl(crawlPage, site.crawl, captureCurrent);
  } finally {
    await context.close();
    await browser.close();
  }

  const finishedAt = new Date().toISOString();
  const status: SiteRunResult["status"] = outcome.errors.length > 0 ? "partial" : "completed";

  const result: SiteRunResult = {
    runId, siteId: site.id, startedAt, finishedAt, status,
    pages, errors: outcome.errors,
  };

  fs.writeFileSync(
    path.join("data", "sites", site.id, "runs", `${runId}.json`),
    JSON.stringify(result, null, 2),
    "utf-8"
  );

  updateSiteRunProgress(site.id, (p) => ({ ...p, status: "completed", updatedAt: finishedAt }));

  return result;
}

const BROWSER_NORMALIZE_FN = (config: { ignoreSelectors: string[]; normalizeWhitespace: boolean }) => {
  const ID_ATTRS = new Set([
    "aria-describedby", "aria-labelledby", "aria-controls", "aria-owns", "id", "for",
  ]);
  const ID_RE = /-?[a-z0-9]{6,}/gi;

  const doc = document.cloneNode(true) as Document;
  doc.querySelectorAll("script, style, noscript").forEach((n) => n.remove());
  for (const sel of config.ignoreSelectors) {
    doc.querySelectorAll(sel).forEach((n) => n.remove());
  }

  const walk = (node: Element | null): void => {
    if (!node) return;
    if (node.attributes) {
      const attrs = Array.from(node.attributes);
      const sorted = attrs
        .map((a) => ({
          name: a.name,
          value: ID_ATTRS.has(a.name) ? a.value.replace(ID_RE, "<id>") : a.value,
        }))
        .sort((x, y) => x.name.localeCompare(y.name));
      for (const a of attrs) node.removeAttribute(a.name);
      for (const { name, value } of sorted) node.setAttribute(name, value);
    }
    for (const child of Array.from(node.childNodes)) {
      if (child.nodeType === 3 && config.normalizeWhitespace) {
        child.textContent = (child.textContent ?? "").replace(/\s+/g, " ").trim();
      } else if (child.nodeType === 1) {
        walk(child as Element);
      }
    }
  };

  walk(doc.body);
  return doc.body ? doc.body.outerHTML : "";
};
```

