26	  page: CrawlPage,
27	  config: SiteCrawlConfig,
28	  onVisit?: (record: VisitRecord) => Promise<void>
29	): Promise<CrawlOutcome> {
30	  const visited = new Set<string>();
31	  const visitedRecords: VisitRecord[] = [];
32	  const skipped: SkipRecord[] = [];
33	  const errors: { url: string; message: string }[] = [];
34	
35	  const queue: { url: string; depth: number }[] = [];
36	  const origins: string[] = [];
37	
38	  for (const raw of config.startUrls) {
39	    const n = normalizeUrl(raw);
40	    if (n) { queue.push({ url: n, depth: 0 }); origins.push(n); }
41	  }
42	
43	  const includeREs = (config.includePatterns ?? []).map((p) => new RegExp(p));
44	  const excludeREs = (config.excludePatterns ?? []).map((p) => new RegExp(p));
45	
46	  while (queue.length > 0) {
47	    if (visited.size >= config.maxPages) {
48	      for (const q of queue) skipped.push({ url: q.url, reason: "limit" });
49	      break;
50	    }
51	
52	    const next = queue.shift();
53	    if (!next) break;
54	
55	    if (visited.has(next.url)) { skipped.push({ url: next.url, reason: "duplicate" }); continue; }
56	    if (next.depth > config.maxDepth) { skipped.push({ url: next.url, reason: "depth" }); continue; }
57	    if (!isHttpUrl(next.url)) { skipped.push({ url: next.url, reason: "non-http" }); continue; }
58	
59	    const internal = origins.some((o) => sameOrigin(o, next.url, config.allowSubdomains));
60	    if (!internal) { skipped.push({ url: next.url, reason: "external" }); continue; }
61	
62	    if (excludeREs.some((re) => re.test(next.url))) {
63	      skipped.push({ url: next.url, reason: "pattern" }); continue;
64	    }
65	    if (includeREs.length > 0 && !includeREs.some((re) => re.test(next.url))) {
66	      skipped.push({ url: next.url, reason: "pattern" }); continue;
67	    }
68	
69	    visited.add(next.url);
70	
71	    try {
72	      const response = await page.goto(next.url);
73	      const finalUrl = response?.url() ?? next.url;
74	      const status = response?.status() ?? 0;
75	      const record: VisitRecord = { url: next.url, finalUrl, httpStatus: status, depth: next.depth };
76	      visitedRecords.push(record);
77	      if (onVisit) await onVisit(record);
78	
79	      if (next.depth < config.maxDepth) {
80	        for (const raw of await page.getLinks()) {
81	          if (!isHttpUrl(raw) && !raw.startsWith("/") && !raw.startsWith("./") && !raw.startsWith("../")) {
82	            skipped.push({ url: raw, reason: "non-http" });
83	            continue;
84	          }
85	          const normalized = normalizeUrl(raw, finalUrl);
86	          if (!normalized) continue;
87	          if (!visited.has(normalized)) queue.push({ url: normalized, depth: next.depth + 1 });
88	        }
89	      }
90	    } catch (error) {
91	      errors.push({ url: next.url, message: error instanceof Error ? error.message : String(error) });
92	    }
93	  }
94	
95	  return { visited: visitedRecords, skipped, errors };
96	}
